Here's a single self-contained HTML file that visualizes binary search on a sorted array. Save it as something like "binary_search_visual.html" and open it in a browser. The page shows the array as numbered boxes, an input for the target, and controls: "Step" to advance one iteration, "Auto" to run automatically, "Reset" to restart with a new array, and "Shuffle" to generate a new sorted array. Each step highlights the current search range (light blue), the middle element (orange), and if found it turns green; if the search completes without finding the target, a red message appears.

Paste the whole contents into a file and open it in your browser.

```html
<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width,initial-scale=1" />
<title>Binary Search Visualizer</title>
<style>
  :root{
    --bg:#0f1724;
    --panel:#0b1220;
    --text:#e6eef8;
    --muted:#98a4b5;
    --box:#0b2540;
    --box-border:#163a67;
    --highlight:#cfe9ff;
    --mid:#ffb86b;
    --found:#7ad68a;
    --notfound:#ff7b7b;
  }
  *{box-sizing:border-box;font-family:Inter,ui-sans-serif,system-ui,-apple-system,"Segoe UI",Roboto,"Helvetica Neue",Arial;}
  body{margin:0; background:linear-gradient(180deg,var(--bg), #071025); color:var(--text); min-height:100vh; display:flex; align-items:center; justify-content:center; padding:24px;}
  .card{width:900px; max-width:100%; background:linear-gradient(180deg,var(--panel), #071627); border-radius:12px; padding:20px; box-shadow:0 10px 30px rgba(2,6,23,0.6);}
  h1{margin:0 0 8px 0; font-size:20px;}
  p.lead{margin:0 0 18px 0; color:var(--muted); font-size:13px;}
  .controls{display:flex; gap:8px; flex-wrap:wrap; align-items:center; margin-bottom:16px;}
  .controls input[type="number"]{width:120px; padding:8px 10px; border-radius:8px; border:1px solid rgba(255,255,255,0.06); background:#071a30; color:var(--text); font-size:14px;}
  .controls button{padding:8px 12px; border-radius:8px; border:none; background:#0b3a66; color:var(--text); cursor:pointer; font-weight:600;}
  .controls button.secondary{background:#17486f;}
  .controls button.danger{background:#6b1f28;}
  .controls label{color:var(--muted); font-size:13px;}
  .top-row{display:flex; gap:16px; align-items:center; margin-bottom:14px; flex-wrap:wrap;}
  .array-wrap{padding:12px; border-radius:10px; background:linear-gradient(180deg,#06142888,#04243a66); border:1px solid rgba(255,255,255,0.03);}
  .array{display:flex; gap:8px; padding:8px 4px; overflow:auto;}
  .cell{min-width:52px; height:52px; border-radius:8px; background:var(--box); border:2px solid var(--box-border); display:flex; align-items:center; justify-content:center; color:var(--text); font-weight:700; font-size:16px; position:relative; flex-shrink:0;}
  .cell .idx{position:absolute; top:4px; left:6px; font-size:11px; color:var(--muted); font-weight:600;}
  .cell.range{background:linear-gradient(180deg, rgba(207,233,255,0.12), rgba(15,58,96,0.12)); border-color:rgba(207,233,255,0.16);}
  .cell.mid{background:linear-gradient(180deg, rgba(255,184,107,0.16), rgba(96,42,5,0.06)); border-color:rgba(255,184,107,0.22);}
  .cell.found{background:linear-gradient(180deg, rgba(122,214,138,0.14), rgba(12,55,12,0.04)); border-color:rgba(122,214,138,0.28);}
  .cell.notfound{background:linear-gradient(180deg, rgba(255,123,123,0.12), rgba(60,12,12,0.04)); border-color:rgba(255,123,123,0.28);}
  .legend{display:flex; gap:10px; margin-top:10px; color:var(--muted); font-size:13px; flex-wrap:wrap;}
  .legend span{display:inline-flex; gap:6px; align-items:center;}
  .sw{width:14px; height:14px; border-radius:3px; display:inline-block; border:2px solid rgba(255,255,255,0.04);}
  .sw.range{background:var(--highlight); border-color:rgba(207,233,255,0.3);}
  .sw.mid{background:var(--mid); border-color:rgba(255,184,107,0.4);}
  .sw.found{background:var(--found); border-color:rgba(122,214,138,0.4);}
  .sw.notfound{background:var(--notfound); border-color:rgba(255,123,123,0.4);}
  .status{margin-top:12px; font-size:15px; min-height:22px; color:var(--muted);}
  .status strong{color:var(--text);}
  .footer{display:flex; justify-content:space-between; align-items:center; margin-top:14px; gap:12px; flex-wrap:wrap;}
  .small{font-size:13px; color:var(--muted);}
  .info{background:rgba(255,255,255,0.02); padding:8px 10px; border-radius:8px; font-size:13px;}
  @media (max-width:600px){
    .cell{min-width:44px; height:44px; font-size:14px;}
  }
</style>
</head>
<body>
  <div class="card" role="main">
    <h1>Binary Search Visualizer</h1>
    <p class="lead">Enter a target value and step through binary search on a sorted array. The current search range is highlighted, the middle element is marked, and results are shown when it's found or when the search finishes.</p>

    <div class="controls top-row">
      <label>
        Target:
        <input id="targetInput" type="number" value="23" />
      </label>

      <button id="stepBtn">Step</button>
      <button id="autoBtn" class="secondary">Auto</button>
      <button id="resetBtn" class="secondary">Reset</button>
      <button id="shuffleBtn" class="secondary">Shuffle</button>

      <label style="margin-left:auto;">
        Array size:
        <input id="sizeInput" type="number" min="5" max="40" value="13" style="width:78px; padding:6px 8px; border-radius:8px; background:#071a30; color:var(--text); border:1px solid rgba(255,255,255,0.06);" />
      </label>
    </div>

    <div class="array-wrap">
      <div id="array" class="array" aria-live="polite" aria-label="Array elements"></div>
    </div>

    <div class="legend">
      <span><i class="sw range"></i> Current search range</span>
      <span><i class="sw mid"></i> Middle element</span>
      <span><i class="sw found"></i> Found</span>
      <span><i class="sw notfound"></i> Not found</span>
    </div>

    <div class="status" id="status">Ready. Enter a target and press Step or Auto.</div>

    <div class="footer">
      <div class="small info" id="stats">low: — &nbsp; mid: — &nbsp; high: — &nbsp; steps: 0</div>
      <div class="small">Tip: You can change array size, shuffle to create a new sorted array, or reset to start the search over.</div>
    </div>
  </div>

<script>
(function(){
  // Utilities
  function randInt(a,b){return Math.floor(Math.random()*(b-a+1))+a;}
  function clamp(v,a,b){return Math.max(a, Math.min(b, v));}

  // DOM
  const arrayEl = document.getElementById('array');
  const targetInput = document.getElementById('targetInput');
  const stepBtn = document.getElementById('stepBtn');
  const autoBtn = document.getElementById('autoBtn');
  const resetBtn = document.getElementById('resetBtn');
  const shuffleBtn = document.getElementById('shuffleBtn');
  const sizeInput = document.getElementById('sizeInput');
  const statusEl = document.getElementById('status');
  const statsEl = document.getElementById('stats');

  // State
  let arr = [];
  let low = 0, high = -1, mid = -1;
  let steps = 0;
  let running = false;
  let autoTimer = null;
  let finished = false;

  function generateSortedArray(n){
    // Generate sorted unique-ish numbers
    const start = randInt(0,6);
    const a = [];
    let val = start;
    for(let i=0;i<n;i++){
      val += randInt(1,6);
      a.push(val);
    }
    return a;
  }

  function renderArray(){
    arrayEl.innerHTML = '';
    arr.forEach((v,i)=>{
      const cell = document.createElement('div');
      cell.className = 'cell';
      cell.setAttribute('data-idx', i);
      const idxSpan = document.createElement('div');
      idxSpan.className = 'idx';
      idxSpan.textContent = i;
      cell.appendChild(idxSpan);
      const val = document.createElement('div');
      val.textContent = v;
      cell.appendChild(val);

      // apply classes
      if(low<=i && i<=high && !finished) cell.classList.add('range');
      if(i===mid && !finished) cell.classList.add('mid');
      if(finished && i===mid && arr[i] === Number(targetInput.value) && mid>=0 && mid < arr.length) cell.classList.add('found');
      if(finished && !(low<=i && i<=high) && arr[i] !== Number(targetInput.value) && i===mid && mid>=0 && mid < arr.length) {
        // no-op; handled above
      }
      arrayEl.appendChild(cell);
    });
    updateStats();
  }

  function updateStats(){
    statsEl.textContent = `low: ${low>=0?low:'—'}  mid: ${mid>=0?mid:'—'}  high: ${high>=0?high:'—'}  steps: ${steps}`;
  }

  function setStatus(msg, tone){
    statusEl.textContent = msg;
    if(tone==='ok') statusEl.style.color = '';
    else if(tone==='warn') statusEl.style.color = 'var(--muted)';
    else if(tone==='err') statusEl.style.color = 'var(--notfound)';
    else statusEl.style.color = '';
  }

  function startSearch(){
    steps = 0;
    low = 0;
    high = arr.length - 1;
    mid = -1;
    finished = false;
    renderArray();
    setStatus('Search started. Press Step to iterate or Auto to run.', 'warn');
  }

  function step(){
    if(finished) return;
    if(low>high){
      finished = true;
      mid = -1;
      renderArray();
      setStatus(`Not found. Target ${targetInput.value} is not in the array.`, 'err');
      return;
    }
    mid = Math.floor((low + high) / 2);
    steps++;
    renderArray();

    const target = Number(targetInput.value);
    if(arr[mid] === target){
      finished = true;
      renderArray();
      // highlight found cell
      const cell = arrayEl.querySelector(`.cell[data-idx="${mid}"]`);
      if(cell){ cell.classList.remove('mid'); cell.classList.add('found'); }
      setStatus(`Found target ${target} at index ${mid} in ${steps} step${steps===1?'':'s'}.`, 'ok');
      stopAuto();
      return;
    } else if (arr[mid] < target){
      setStatus(`Step ${steps}: arr[${mid}] = ${arr[mid]} < ${target} → move low to ${mid + 1}`, 'warn');
      low = mid + 1;
    } else {
      setStatus(`Step ${steps}: arr[${mid}] = ${arr[mid]} > ${target} → move high to ${mid - 1}`, 'warn');
      high = mid - 1;
    }

    // if next step will be impossible, handle not found on next call
    if(low>high){
      // show the empty range briefly
      renderArray();
    }
  }

  function stopAuto(){
    running = false;
    autoBtn.textContent = 'Auto';
    if(autoTimer){ clearInterval(autoTimer); autoTimer = null; }
  }

  function runAuto(){
    if(running){
      stopAuto();
      return;
    }
    if(finished){
      setStatus('Search already finished. Reset to start again.', 'warn');
      return;
    }
    running = true;
    autoBtn.textContent = 'Stop';
    autoTimer = setInterval(()=>{
      if(finished) { stopAuto(); return; }
      // if no progress possible, do a final call
      if(low>high){ step(); stopAuto(); return; }
      step();
      if(finished) stopAuto();
    }, 700);
  }

  function reset(){
    stopAuto();
    startSearch();
  }

  function shuffle(){
    stopAuto();
    const n = clamp(Number(sizeInput.value) || 13, 5, 40);
    arr = generateSortedArray(n);
    // adjust target default to a value likely present or not
    targetInput.value = arr[Math.floor(arr.length/2)];
    startSearch();
  }

  // initialize
  shuffle();

  // events
  stepBtn.addEventListener('click', ()=>{
    stopAuto();
    if(finished){
      setStatus('Search finished. Reset to start again or Shuffle to create a new array.', 'warn');
      return;
    }
    if(low>high){
      // call step will mark not found
      step();
      return;
    }
    step();
  });

  autoBtn.addEventListener('click', ()=>{
    runAuto();
  });

  resetBtn.addEventListener('click', ()=>{
    targetInput.value = '';
    stopAuto();
    startSearch();
  });

  shuffleBtn.addEventListener('click', ()=>{
    shuffle();
  });

  sizeInput.addEventListener('change', ()=>{
    const v = clamp(Number(sizeInput.value) || 13, 5, 40);
    sizeInput.value = v;
  });

  targetInput.addEventListener('keydown', (e)=>{
    if(e.key === 'Enter'){
      stopAuto();
      startSearch();
      // optional: step immediately
      step();
    }
  });

  // Click on a cell to set target quickly
  arrayEl.addEventListener('click', (e)=>{
    const cell = e.target.closest('.cell');
    if(!cell) return;
    const idx = Number(cell.getAttribute('data-idx'));
    if(Number.isFinite(idx)){
      targetInput.value = arr[idx];
    }
  });

  // accessibility: focus styles with keyboard
  document.addEventListener('keydown', (e)=>{
    if(e.key === 's' && (e.ctrlKey || e.metaKey)) { // Ctrl/Cmd+S to step
      e.preventDefault();
      stepBtn.click();
    }
  });

})();
</script>
</body>
</html>
```

If you want any changes — for example different colors, slower/faster auto-run interval, showing comparisons visually (arrows), or supporting strings instead of numbers — tell me which and I’ll adapt it.

Below is a single self-contained HTML file that visualizes binary search step-by-step. Save it as something like binary_search_visualizer.html and open it in a browser. Features:
- Editable sorted array (comma-separated values)
- Target input
- "Step" button to advance one binary-search iteration (highlights low/mid/high and the searched mid)
- "Auto" to run steps with a delay
- "Reset" to restart the search
- Shows status: found index or not found after the algorithm completes
- Prevents invalid inputs and keeps array sorted (it will sort numeric input)

Paste the whole text into a file and open in a browser.

```html
<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8"/>
  <title>Binary Search Visualizer</title>
  <meta name="viewport" content="width=device-width,initial-scale=1"/>
  <style>
    :root{
      --bg:#f7f9fc;
      --card:#ffffff;
      --accent:#2b8cff;
      --accent-2:#22c55e;
      --muted:#6b7280;
      --danger:#ef4444;
      --box:#eef2ff;
    }
    html,body{height:100%;margin:0;font-family:Inter,ui-sans-serif,system-ui,Segoe UI,Roboto,"Helvetica Neue",Arial;}
    body{background:linear-gradient(180deg,var(--bg),#eef6ff);display:flex;align-items:flex-start;justify-content:center;padding:32px;}
    .container{width:980px;max-width:96%;background:var(--card);box-shadow:0 8px 30px rgba(16,24,40,0.08);border-radius:12px;padding:20px;}
    h1{margin:0 0 10px;font-size:20px;}
    .controls{display:flex;gap:12px;align-items:center;margin-bottom:12px;flex-wrap:wrap;}
    .controls label{font-size:13px;color:var(--muted);display:flex;flex-direction:column;gap:6px;}
    input[type="text"], input[type="number"]{
      padding:10px 12px;border-radius:8px;border:1px solid #e6eef8;background:#fff;min-width:160px;
      box-sizing:border-box;font-size:14px;
    }
    button{padding:10px 14px;border-radius:8px;border:0;background:var(--accent);color:#fff;font-weight:600;cursor:pointer;}
    button.secondary{background:#e6eef8;color:#1f2937;}
    button.danger{background:var(--danger);box-shadow:none;}
    button:disabled{opacity:0.5;cursor:not-allowed;}
    .array-row{display:flex;gap:8px;flex-wrap:wrap;padding:18px 12px;border-radius:10px;background:linear-gradient(180deg,#fafcff,#ffffff);border:1px solid #eef3ff;margin-bottom:12px;}
    .cell{width:56px;height:56px;background:var(--box);display:flex;align-items:center;justify-content:center;border-radius:8px;font-weight:700;color:#0f172a;position:relative;box-shadow:inset 0 -4px 6px rgba(15,23,42,0.02);}
    .index{position:absolute;bottom:4px;right:6px;font-size:11px;color:var(--muted);font-weight:600}
    .cell.mid{box-shadow:0 6px 18px rgba(43,140,255,0.15), inset 0 -4px 6px rgba(15,23,42,0.02);border:2px solid rgba(43,140,255,0.18);}
    .cell.low{outline:3px solid rgba(34,197,94,0.12);border-radius:10px;}
    .cell.high{outline:3px dashed rgba(239,68,68,0.08);border-radius:10px;}
    .cell.searched{background:#fff3cd;border:2px solid #f59e0b;}
    .legend{display:flex;gap:10px;align-items:center;margin-top:8px;}
    .legend .item{display:flex;align-items:center;gap:8px;font-size:13px;color:var(--muted);}
    .legend .swatch{width:14px;height:14px;border-radius:4px;}
    .status{padding:12px;border-radius:8px;background:#f8fafc;border:1px solid #eef2ff;margin-top:12px;font-size:14px;}
    .small{font-size:13px;color:var(--muted)}
    footer{margin-top:14px;font-size:12px;color:var(--muted);text-align:right}
    @media (max-width:640px){
      .cell{width:48px;height:48px}
    }
  </style>
</head>
<body>
  <div class="container">
    <h1>Binary Search Visualizer</h1>
    <div class="controls">
      <label>
        Array (comma separated, numbers)
        <input id="arrayInput" type="text" value="1,3,5,7,9,11,13,15" />
      </label>

      <label>
        Target
        <input id="targetInput" type="number" value="7" />
      </label>

      <button id="stepBtn">Step</button>
      <button id="autoBtn" class="secondary">Auto</button>
      <button id="resetBtn" class="secondary">Reset</button>
      <button id="shuffleBtn" class="secondary">Randomize</button>

      <div style="margin-left:auto;text-align:right">
        <div class="small">Low, Mid, High highlights; searched mid is orange</div>
      </div>
    </div>

    <div id="arrayContainer" class="array-row" aria-live="polite"></div>

    <div class="legend">
      <div class="item"><span class="swatch" style="background:rgba(34,197,94,0.3);border:2px solid rgba(34,197,94,0.25)"></span> Low</div>
      <div class="item"><span class="swatch" style="background:rgba(43,140,255,0.18);border:2px solid rgba(43,140,255,0.2)"></span> Mid</div>
      <div class="item"><span class="swatch" style="background:rgba(239,68,68,0.08);border:2px dashed rgba(239,68,68,0.12)"></span> High</div>
      <div class="item"><span class="swatch" style="background:#fff3cd;border:2px solid #f59e0b"></span> Searched</div>
    </div>

    <div id="status" class="status">Press Step to advance one iteration.</div>

    <footer>Visualization steps through the classic binary search algorithm on a sorted numeric array.</footer>
  </div>

  <script>
    // Binary Search Visualizer JS
    (function(){
      const arrayInput = document.getElementById('arrayInput');
      const targetInput = document.getElementById('targetInput');
      const stepBtn = document.getElementById('stepBtn');
      const autoBtn = document.getElementById('autoBtn');
      const resetBtn = document.getElementById('resetBtn');
      const shuffleBtn = document.getElementById('shuffleBtn');
      const arrayContainer = document.getElementById('arrayContainer');
      const statusEl = document.getElementById('status');

      let arr = [];
      let low = 0;
      let high = -1;
      let mid = -1;
      let done = false;
      let foundIndex = -1;
      let searchedIndices = new Set();
      let autoTimer = null;
      let delay = 700;

      function parseArrayInput(){
        const raw = arrayInput.value.trim();
        if(!raw) return [];
        // parse numbers, ignore empties
        const parts = raw.split(',').map(s=>s.trim()).filter(s=>s.length>0);
        const nums = parts.map(s=>{
          const n = Number(s);
          return isNaN(n) ? null : n;
        });
        // If any non-number, fallback to empty
        if(nums.some(n=>n===null)) return null;
        // sort ascending by numeric value
        nums.sort((a,b)=>a-b);
        return nums;
      }

      function renderArray(){
        arrayContainer.innerHTML = '';
        if(!arr.length){
          arrayContainer.textContent = '(array is empty)';
          return;
        }
        for(let i=0;i<arr.length;i++){
          const c = document.createElement('div');
          c.className='cell';
          c.textContent = arr[i];
          const idx = document.createElement('div');
          idx.className='index';
          idx.textContent = i;
          c.appendChild(idx);

          if(i===mid) c.classList.add('mid');
          if(i===low) c.classList.add('low');
          if(i===high) c.classList.add('high');
          if(searchedIndices.has(i)) c.classList.add('searched');

          arrayContainer.appendChild(c);
        }
      }

      function setStatus(msg, tone){
        statusEl.textContent = msg;
        if(tone==='ok') statusEl.style.borderColor = '#dcfce7';
        else if(tone==='err') statusEl.style.borderColor = '#fee2e2';
        else statusEl.style.borderColor = '#eef2ff';
      }

      function resetSearch(preserveInputs){
        const parsed = parseArrayInput();
        if(parsed === null){
          setStatus('Invalid array: please enter comma separated numbers.', 'err');
          return false;
        }
        arr = parsed;
        low = 0;
        high = arr.length - 1;
        mid = -1;
        done = false;
        foundIndex = -1;
        searchedIndices = new Set();
        if(!preserveInputs){
          // keep inputs as-is
        }
        renderArray();
        setStatus('Search reset. Press Step to begin.', null);
        stepBtn.disabled = arr.length === 0;
        return true;
      }

      function step(){
        if(done) return;
        if(low > high){
          // not found
          done = true;
          setStatus('Target not found in the array.', 'err');
          renderArray();
          return;
        }
        mid = Math.floor((low + high) / 2);
        searchedIndices.add(mid);
        renderArray();

        const target = Number(targetInput.value);
        if(isNaN(target)){
          setStatus('Invalid target: enter a number.', 'err');
          return;
        }

        if(arr[mid] === target){
          done = true;
          foundIndex = mid;
          setStatus('Found target at index ' + mid + '.', 'ok');
          renderArray();
          return;
        } else if(arr[mid] < target){
          // search right half
          low = mid + 1;
          setStatus('Value at mid ('+arr[mid]+') is less than target. Move low to '+low+'.', null);
        } else {
          // search left half
          high = mid - 1;
          setStatus('Value at mid ('+arr[mid]+') is greater than target. Move high to '+high+'.', null);
        }

        // if search completes next time, step will detect low>high
        renderArray();
      }

      function startAuto(){
        if(autoTimer) return stopAuto();
        autoBtn.textContent = 'Stop';
        autoBtn.classList.add('danger');
        autoTimer = setInterval(()=>{
          if(done || low>high){
            stopAuto();
            if(!done){
              done = true;
              setStatus('Target not found in the array.', 'err');
            }
            return;
          }
          step();
          if(done) stopAuto();
        }, delay);
      }
      function stopAuto(){
        if(autoTimer) clearInterval(autoTimer);
        autoTimer = null;
        autoBtn.textContent = 'Auto';
        autoBtn.classList.remove('danger');
      }

      // Event listeners
      stepBtn.addEventListener('click', ()=>{
        if(!arr.length){
          setStatus('Array is empty. Enter numbers to search.', 'err');
          return;
        }
        if(parseArrayInput()===null){
          setStatus('Invalid array: please enter comma separated numbers.', 'err');
          return;
        }
        if(isNaN(Number(targetInput.value))){
          setStatus('Enter a numeric target.', 'err');
          return;
        }
        step();
      });

      autoBtn.addEventListener('click', ()=>{
        if(!arr.length){
          setStatus('Array is empty. Enter numbers to search.', 'err');
          return;
        }
        if(parseArrayInput()===null){
          setStatus('Invalid array: please enter comma separated numbers.', 'err');
          return;
        }
        if(isNaN(Number(targetInput.value))){
          setStatus('Enter a numeric target.', 'err');
          return;
        }
        if(autoTimer) stopAuto();
        else startAuto();
      });

      resetBtn.addEventListener('click', ()=>{
        stopAuto();
        resetSearch(true);
      });

      shuffleBtn.addEventListener('click', ()=>{
        stopAuto();
        // create random sorted array
        const len = Math.floor(Math.random()*8)+5;
        const base = Math.floor(Math.random()*5);
        const nums = [];
        let cur = base;
        for(let i=0;i<len;i++){
          cur += Math.floor(Math.random()*4)+1;
          nums.push(cur);
        }
        arrayInput.value = nums.join(',');
        targetInput.value = nums[Math.floor(Math.random()*nums.length)];
        resetSearch(true);
      });

      arrayInput.addEventListener('change', ()=>{
        stopAuto();
        resetSearch(true);
      });
      targetInput.addEventListener('change', ()=>{ stopAuto(); });

      // initialize
      resetSearch(false);

      // keyboard: Space to step, Enter to auto toggle
      window.addEventListener('keydown',(e)=>{
        if(e.target.tagName==='INPUT') return;
        if(e.code === 'Space'){ e.preventDefault(); stepBtn.click(); }
        if(e.code === 'Enter'){ e.preventDefault(); autoBtn.click(); }
      });

    })();
  </script>
</body>
</html>
