<body>
<div class="container">
  <header>
    <h1>Binary Search Visualizer</h1>
    <div class="controls">
      <label style="color:var(--muted);font-weight:600">Target</label>
      <input id="targetInput" type="number" value="34" />
      <button id="stepBtn" class="small">Step</button>
      <button id="runBtn" class="small">Run</button>
      <button id="resetBtn" class="small secondary">Reset</button>
    </div>
  </header>

  <div class="main">
    <div class="visual">
      <div class="array" id="arrayContainer" aria-live="polite"></div>
      <div class="legend">
        <div class="item"><div class="swatch sw-range"></div><div>Current search range</div></div>
        <div class="item"><div class="swatch sw-mid"></div><div>Middle element</div></div>
      </div>
      <div class="hint">Click Step to advance one iteration. Run animates automatically. Reset restores initial array and state.</div>
    </div>

    <div class="info">
      <h2>State</h2>
      <div class="state">low: <span id="lowVal">-</span>, high: <span id="highVal">-</span>, mid: <span id="midVal">-</span></div>
      <div class="state">Comparisons: <span id="cmpCount">0</span></div>
      <div class="log" id="logArea" aria-live="polite"></div>
      <div class="result" id="resultArea"></div>
    </div>
  </div>

  <footer>Array is sorted ascending. Example array is preset, you can modify the code to change it.</footer>
</div>

<script>
(function(){
  // Initial sorted array - modify here if you want a different set
  const initialArray = [3,7,12,14,19,23,27,34,38,41,45,52];
  // UI elements
  const arrayContainer = document.getElementById('arrayContainer');
  const lowVal = document.getElementById('lowVal');
  const highVal = document.getElementById('highVal');
  const midVal = document.getElementById('midVal');
  const logArea = document.getElementById('logArea');
  const resultArea = document.getElementById('resultArea');
  const cmpCountEl = document.getElementById('cmpCount');

  const targetInput = document.getElementById('targetInput');
  const stepBtn = document.getElementById('stepBtn');
  const runBtn = document.getElementById('runBtn');
  const resetBtn = document.getElementById('resetBtn');

  let arr = initialArray.slice();
  let low = 0, high = arr.length - 1, mid = null;
  let comparisons = 0;
  let finished = false;
  let running = false;
  let timer = null;

  function renderArray(){
    arrayContainer.innerHTML = '';
    arr.forEach((v,i)=>{
      const el = document.createElement('div');
      el.className = 'cell';
      el.dataset.index = i;
      el.innerHTML = '<div class="index">['+i+']</div>' + v;
      // style based on range and mid
      if (finished){
        // if finished and found mark green or red
      }
      if (low <= i && i <= high && !finished){
        el.classList.add('range');
      } else {
        el.classList.add('dim');
      }
      if (i === mid && mid !== null){
        el.classList.add('mid');
      }
      arrayContainer.appendChild(el);
    });
  }

  function log(text){
    const p = document.createElement('div');
    p.textContent = text;
    logArea.insertBefore(p, logArea.firstChild);
  }

  function updateStateDisplay(){
    lowVal.textContent = (low!=null?low:'-');
    highVal.textContent = (high!=null?high:'-');
    midVal.textContent = (mid!=null?mid:'-');
    cmpCountEl.textContent = comparisons;
    renderArray();
  }

  function step(){
    if (finished) return;
    const target = Number(targetInput.value);
    if (!Number.isFinite(target)){
      alert('Please enter a valid number as target.');
      return;
    }
    if (low > high){
      finished = true;
      resultArea.textContent = 'Not found';
      resultArea.style.color = getComputedStyle(document.documentElement).getPropertyValue('--notfound') || '#ef4444';
      log('Range exhausted. Target ' + target + ' not found.');
      updateStateDisplay();
      return;
    }
    mid = Math.floor((low + high) / 2);
    comparisons++;
    log(`Compare target ${target} with arr[${mid}] = ${arr[mid]}`);
    if (arr[mid] === target){
      finished = true;
      resultArea.textContent = 'Found at index ' + mid;
      resultArea.style.color = getComputedStyle(document.documentElement).getPropertyValue('--found') || '#16a34a';
      log(`Found target at index ${mid}.`);
    } else if (arr[mid] < target){
      log(`arr[${mid}] (${arr[mid]}) < ${target} → move low to ${mid + 1}`);
      low = mid + 1;
    } else {
      log(`arr[${mid}] (${arr[mid]}) > ${target} → move high to ${mid - 1}`);
      high = mid - 1;
    }
    updateStateDisplay();

    // If range exhausted after update, mark not found
    if (!finished && low > high){
      finished = true;
      resultArea.textContent = 'Not found';
      resultArea.style.color = getComputedStyle(document.documentElement).getPropertyValue('--notfound') || '#ef4444';
      log('Range exhausted. Target ' + target + ' not found.');
      updateStateDisplay();
    }
  }

  function reset(){
    arr = initialArray.slice();
    low = 0; high = arr.length - 1; mid = null;
    comparisons = 0;
    finished = false;
    running = false;
    if (timer) { clearInterval(timer); timer = null; runBtn.textContent = 'Run'; }
    logArea.innerHTML = '';
    resultArea.textContent = '';
    resultArea.style.color = '';
    updateStateDisplay();
  }

  function runAuto(){
    if (finished){
      running = false;
      runBtn.textContent = 'Run';
      return;
    }
    if (!running){
      running = true;
      runBtn.textContent = 'Pause';
      timer = setInterval(()=>{
        if (finished) { clearInterval(timer); running = false; runBtn.textContent = 'Run'; timer = null; return; }
        step();
      }, 650);
    } else {
      // pause
      running = false;
      runBtn.textContent = 'Run';
      if (timer) { clearInterval(timer); timer = null; }
    }
  }

  // allow clicking a cell to set target quickly
  arrayContainer.addEventListener('click', (e)=>{
    const cell = e.target.closest('.cell');
    if (!cell) return;
    const idx = Number(cell.dataset.index);
    if (!Number.isFinite(idx)) return;
    targetInput.value = arr[idx];
  });

  stepBtn.addEventListener('click', ()=>{ step(); });
  runBtn.addEventListener('click', ()=>{ runAuto(); });
  resetBtn.addEventListener('click', ()=>{ reset(); });

  // initialize
  reset();

  // keyboard: Enter to step
  targetInput.addEventListener('keydown', (e)=>{
    if (e.key === 'Enter') step();
  });

  // make initial rendering accessible
  renderArray();
})();
</script>
</body>
</html>
