        <input id="targetInput" type="number" value="23" />
      </label>

      <button id="startBtn">Start</button>
      <button id="stepBtn" class="small secondary" disabled>Step</button>
      <button id="autoBtn" class="small">Auto ▶</button>
      <button id="backBtn" class="small secondary" disabled>Back ◀</button>
      <label style="display:flex;align-items:center;gap:8px;margin-left:8px">
        Speed
        <input id="speed" type="range" min="200" max="1600" step="100" value="600" />
      </label>

      <div class="legend" title="Legend">
        <div class="item"><span class="sw"></span>range</div>
        <div class="item"><span class="sw mid"></span>mid</div>
        <div style="width:8px"></div>
        <div class="item" style="font-size:13px;color:#333">Array:</div>
      </div>
    </div>

    <div id="arrayWrap" style="min-height:90px">
      <!-- array rendered here -->
    </div>

    <div class="status">
      <div class="msg" id="statusMsg">Press Start to begin</div>
      <div style="margin-left:auto;color:var(--muted);font-size:13px" id="iterInfo"></div>
    </div>

    <div class="footer">The array is sorted and fixed for this demo. You can change the numbers in the code if you want different arrays.</div>
  </div>
</div>

<script>
(function(){
  // Config: change array here if you like
  const ARR = [1,4,7,9,12,15,18,21,23,27,31,34,39];
  const arrayWrap = document.getElementById('arrayWrap');
  const targetInput = document.getElementById('targetInput');
  const startBtn = document.getElementById('startBtn');
  const stepBtn = document.getElementById('stepBtn');
  const backBtn = document.getElementById('backBtn');
  const autoBtn = document.getElementById('autoBtn');
  const statusMsg = document.getElementById('statusMsg');
  const iterInfo = document.getElementById('iterInfo');
  const speedRange = document.getElementById('speed');

  let state = null;
  let autoTimer = null;

  function renderArray(highlightRange=null, mid=null, foundIndex=null, history=null){
    arrayWrap.innerHTML = '';
    const container = document.createElement('div');
    container.className = 'array';

    // create cells
    ARR.forEach((v,i)=>{
      const cell = document.createElement('div');
      cell.className = 'cell';
      const idx = document.createElement('div');
      idx.className = 'idx';
      idx.textContent = i;
      cell.appendChild(idx);
      const txt = document.createElement('div');
      txt.textContent = v;
      cell.appendChild(txt);

      if (foundIndex === i){
        cell.classList.add('found');
      } else if (mid === i){
        cell.classList.add('mid');
      } else if (highlightRange && i >= highlightRange[0] && i <= highlightRange[1]){
        // visually part of range
        cell.style.background = 'linear-gradient(180deg,#f3f8ff,#ffffff)';
        cell.style.border = '1px dashed rgba(13,110,253,0.16)';
      }

      container.appendChild(cell);
    });

    arrayWrap.appendChild(container);
  }

  function initState(){
    return {
      lo: 0,
      hi: ARR.length - 1,
      mid: null,
      stepCount: 0,
      finished: false,
      foundIndex: null,
      history: [] // store snapshots for back
    };
  }

  function start(){
    stopAuto();
    state = initState();
    statusMsg.textContent = 'Searching...';
    stepBtn.disabled = false;
    backBtn.disabled = true;
    autoBtn.textContent = 'Auto ▶';
    iterInfo.textContent = '';
    renderArray([state.lo, state.hi], null, null);
  }

  function computeMid(lo, hi){
    // typical mid formula
    return Math.floor((lo + hi) / 2);
  }

  function stepForward(){
    if (!state || state.finished) return;
    const target = Number(targetInput.value);
    if (Number.isNaN(target)) return;
    // save snapshot for back
    state.history.push({
      lo: state.lo, hi: state.hi, mid: state.mid, stepCount: state.stepCount, foundIndex: state.foundIndex
    });
    backBtn.disabled = false;

    if (state.lo > state.hi){
      // finished - not found
      state.finished = true;
      state.foundIndex = null;
      statusMsg.textContent = 'Not found';
      statusMsg.style.color = '';
      stepBtn.disabled = true;
      renderArray(null, null, null);
      iterInfo.textContent = `Steps: ${state.stepCount}`;
      return;
    }

    const mid = computeMid(state.lo, state.hi);
    state.mid = mid;
    state.stepCount++;

    // render showing mid
    renderArray([state.lo, state.hi], state.mid, null);
    iterInfo.textContent = `lo=${state.lo} hi=${state.hi} mid=${state.mid} steps=${state.stepCount}`;

    // check
    const val = ARR[mid];
    if (val === target){
      state.finished = true;
      state.foundIndex = mid;
      statusMsg.textContent = `Found at index ${mid} (value ${val})`;
      statusMsg.style.color = '';
      stepBtn.disabled = true;
      renderArray([state.lo, state.hi], state.mid, state.foundIndex);
      iterInfo.textContent = `Found in ${state.stepCount} step(s)`;
      stopAuto();
      return;
    } else if (val < target){
      state.lo = mid + 1;
    } else {
      state.hi = mid - 1;
    }

    // if next iteration would be empty, show the range update immediately (so user sees narrowing)
    if (state.lo > state.hi){
      // show final not found state on next step (or when stepping again)
      // update render to show empty range (no highlights)
      renderArray(null, null, null);
    } else {
      // show updated range
      renderArray([state.lo, state.hi], null, null);
    }
  }

  function stepBack(){
    if (!state || state.history.length === 0) return;
    stopAuto();
    const prev = state.history.pop();
    state.lo = prev.lo;
    state.hi = prev.hi;
    state.mid = prev.mid;
    state.stepCount = prev.stepCount;
    state.foundIndex = prev.foundIndex;
    state.finished = false;
    statusMsg.textContent = 'Searching...';
    statusMsg.style.color = '';
    stepBtn.disabled = false;
    if (state.history.length === 0) backBtn.disabled = true;
    renderArray([state.lo, state.hi], state.mid, state.foundIndex);
    iterInfo.textContent = `lo=${state.lo} hi=${state.hi} mid=${state.mid ?? '-'} steps=${state.stepCount}`;
  }

  function autoToggle(){
    if (autoTimer){
      stopAuto();
      autoBtn.textContent = 'Auto ▶';
      return;
    }
    if (!state || state.finished){
      start();
    }
    autoBtn.textContent = 'Stop ⏸';
    runAuto();
  }

  function runAuto(){
    const interval = Number(speedRange.value) || 600;
    autoTimer = setInterval(()=>{
      if (!state || state.finished){
        stopAuto();
        autoBtn.textContent = 'Auto ▶';
        return;
      }
      stepForward();
    }, interval);
  }

  function stopAuto(){
    if (autoTimer){
      clearInterval(autoTimer);
      autoTimer = null;
    }
    autoBtn.textContent = 'Auto ▶';
  }

  // initial render
  renderArray([0, ARR.length-1], null, null);
  iterInfo.textContent = '';

  // events
  startBtn.addEventListener('click', ()=>{
    start();
  });
  stepBtn.addEventListener('click', ()=>{
    stepForward();
  });
  backBtn.addEventListener('click', ()=>{
    stepBack();
  });
  autoBtn.addEventListener('click', ()=>{
    autoToggle();
  });
  speedRange.addEventListener('input', ()=>{
    if (autoTimer){
      stopAuto();
      runAuto();
    }
  });

  // allow Enter to start
  targetInput.addEventListener('keydown', (e)=>{
    if (e.key === 'Enter') start();
  });

})();
</script>
</body>
</html>

