  <script>
    // Simple binary search visualizer logic
    (function(){
      // UI elements
      const arrayRow = document.getElementById('arrayRow');
      const targetInput = document.getElementById('target');
      const startBtn = document.getElementById('startBtn');
      const stepBtn = document.getElementById('stepBtn');
      const resetBtn = document.getElementById('resetBtn');
      const autoBtn = document.getElementById('autoBtn');
      const msg = document.getElementById('message');
      const indicesEl = document.getElementById('indices');
      const preset = document.getElementById('preset');

      // State
      let arr = [];
      let low = 0, high = -1, mid = -1;
      let running = false;
      let finished = false;
      let timer = null;

      function makeArray(type){
        if(type === 'even'){
          return [3,8,12,17,25,33,41,49,58,66];
        }
        if(type === 'random'){
          const n = 11;
          const a = [];
          let v = 2;
          for(let i=0;i<n;i++){ v += Math.floor(Math.random()*9)+1; a.push(v); }
          return a;
        }
        // default
        return [2,5,11,19,27,33,38,45,53,61,73,89,97];
      }

      function render(){
        arrayRow.innerHTML = '';
        arr.forEach((v,i)=>{
          const el = document.createElement('div');
          el.className = 'cell';
          el.dataset.index = i;
          const idx = document.createElement('div');
          idx.className = 'index';
          idx.textContent = i;
          const val = document.createElement('div');
          val.className = 'value';
          val.textContent = v;
          el.appendChild(idx);
          el.appendChild(val);

          // styling based on state
          if(running || finished){
            if(i < low || i > high){
              el.classList.add('out');
            } else {
              el.classList.add('range');
            }
            if(i === mid){
              el.classList.remove('range');
              if(finished && arr[mid] === Number(targetInput.value) ){
                el.classList.add('found');
              } else {
                el.classList.add('mid');
              }
            }
          }
          arrayRow.appendChild(el);
        });

        // update indices message
        indicesEl.textContent = `low: ${low>=0?low:'—'}   mid: ${mid>=0?mid:'—'}   high: ${high>=0?high:'—'}`;
      }

      function resetState(){
        arr = makeArray(preset.value);
        low = 0; high = arr.length - 1; mid = -1;
        running = false; finished = false;
        clearTimer();
        stepBtn.disabled = true; autoBtn.disabled = true;
        msg.textContent = 'Press Start to begin.';
        render();
      }

      function clearTimer(){
        if(timer){ clearInterval(timer); timer = null; autoBtn.textContent = 'Auto Run'; }
      }

      function startRun(){
        // initialize search
        const t = Number(targetInput.value);
        if(Number.isNaN(t)){
          msg.textContent = 'Please enter a valid number target.';
          return;
        }
        running = true;
        finished = false;
        low = 0; high = arr.length - 1; mid = -1;
        stepBtn.disabled = false; autoBtn.disabled = false;
        msg.textContent = 'Running. Use Step to advance.';
        render();
      }

      function step(){
        if(finished) return;
        if(!running){
          msg.textContent = 'Press Start first.';
          return;
        }
        if(low > high){
          // not found
          finished = true;
          render();
          msg.textContent = `Not found (${targetInput.value}) in array.`;
          stepBtn.disabled = true; autoBtn.disabled = true;
          return;
        }
        mid = Math.floor((low + high)/2);
        render();
        // compare
        const t = Number(targetInput.value);
        const val = arr[mid];
        if(val === t){
          finished = true;
          render();
          msg.textContent = `Found ${t} at index ${mid}.`;
          stepBtn.disabled = true; autoBtn.disabled = true;
          return;
        } else if(val < t){
          msg.textContent = `Comparing: arr[${mid}] = ${val} < ${t} → move low to ${mid + 1}`;
          low = mid + 1;
        } else {
          msg.textContent = `Comparing: arr[${mid}] = ${val} > ${t} → move high to ${mid - 1}`;
          high = mid - 1;
        }
        render();
      }

      // Auto-run toggling
      function toggleAuto(){
        if(timer){
          clearTimer();
          return;
        }
        if(!running || finished){ return; }
        autoBtn.textContent = 'Stop';
        timer = setInterval(()=>{
          if(finished){ clearTimer(); return; }
          step();
        }, 600);
      }

      // Event bindings
      startBtn.addEventListener('click', ()=>{
        resetState();
        startRun();
      });

      stepBtn.addEventListener('click', step);

      resetBtn.addEventListener('click', ()=>{
        clearTimer();
        // restore arr from preset and clear target?
        // keep target as-is but re-enable controls
        resetState();
      });

      autoBtn.addEventListener('click', ()=>{
        toggleAuto();
      });

      preset.addEventListener('change', ()=>{
        resetState();
      });

      // init
      resetState();

      // make array accessible via keyboard: Enter in target starts run
      targetInput.addEventListener('keydown', (e)=>{
        if(e.key === 'Enter'){
          startBtn.click();
        }
      });

    })();
  </script>
</body>
</html>
