          <div style="font-size:13px;color:var(--muted);margin-bottom:6px">Step log</div>
          <div id="log" class="log">No steps yet.</div>
        </div>

        <div style="width:220px;min-width:200px">
          <div style="font-size:13px;color:var(--muted);margin-bottom:6px">Search indices</div>
          <div style="background:var(--box);padding:10px;border-radius:8px;border:1px solid var(--box-border);">
            <div style="display:flex;justify-content:space-between;margin-bottom:8px"><div style="color:var(--muted)">low</div><div id="lowVal">—</div></div>
