  <script>
    // Utility parsing
    function parseArray(text){
      if(!text) return [];
      return text.split(',')
        .map(s => s.trim())
        .filter(s => s.length>0)
        .map(s => {
          // parse as number if possible; otherwise NaN
          const n = Number(s);
          return isNaN(n) ? NaN : n;
        });
    }

    // DOM
    const arrayInput = document.getElementById('arrayInput');
    const applyArray = document.getElementById('applyArray');
    const targetInput = document.getElementById('targetInput');
    const startSearch = document.getElementById('startSearch');
    const arrayContainer = document.getElementById('arrayContainer');
    const statusText = document.getElementById('statusText');
    const logEl = document.getElementById('log');
    const lowVal = document.getElementById('lowVal');
    const highVal = document.getElementById('highVal');
    const midVal = document.getElementById('midVal');
    const stepBtn = document.getElementById('stepBtn');
    const runBtn = document.getElementById('runBtn');
    const resetBtn = document.getElementById('resetBtn');
    const resultPill = document.getElementById('resultPill');

    let arr = parseArray(arrayInput.value);
    let target = null;
    let state = 'idle'; // 'idle', 'running', 'finished'
    let low = 0, high = -1, mid = -1;
    let foundIndex = -1;
    let autoTimer = null;

    function renderArray(){
      arrayContainer.innerHTML = '';
      arr.forEach((v,i) => {
        const cell = document.createElement('div');
        cell.className = 'cell';
        cell.setAttribute('data-idx', i);
        const idx = document.createElement('div');
        idx.className = 'idx-label';
        idx.textContent = i;
        const val = document.createElement('div');
        val.className = 'val';
        val.textContent = isNaN(v) ? 'NaN' : v;
        cell.appendChild(idx);
        cell.appendChild(val);
        arrayContainer.appendChild(cell);
      });
      updateHighlights();
    }

    function clamp(n, a, b){ return Math.max(a, Math.min(b, n)); }

    function updateHighlights(){
      const cells = Array.from(arrayContainer.children);
      cells.forEach((el, i) => {
        el.classList.remove('highlight-range','mid','found','out-of-range');
        if(state === 'idle'){
          // nothing special
        } else {
          if(i < low || i > high){
            el.classList.add('out-of-range');
          } else {
            el.classList.add('highlight-range');
          }
          if(i === mid){
            el.classList.add('mid');
          }
          if(foundIndex === i){
            el.classList.remove('mid');
            el.classList.add('found');
          }
        }
      });
      lowVal.textContent = (low<=high) ? low : '—';
      highVal.textContent = (low<=high) ? high : '—';
      midVal.textContent = (mid>=0 && mid<=arr.length-1) ? mid : '—';
    }

    function log(msg){
