        logEl.textContent = '';
      }
      const p = document.createElement('div');
      p.style.padding = '6px 0';
      p.style.borderBottom = '1px dashed rgba(255,255,255,0.02)';
      p.style.fontSize = '13px';
      p.style.color = 'var(--muted)';
      p.textContent = `[${time}] ${msg}`;
      logEl.insertBefore(p, logEl.firstChild);
    }

    function setStatus(msg, kind){
      statusText.textContent = msg;
      resultPill.style.display = 'none';
      if(kind === 'found'){
        resultPill.textContent = 'Found';
        resultPill.className = 'result-pill result-found';
        resultPill.style.display = 'inline-block';
      } else if(kind === 'notfound'){
        resultPill.textContent = 'Not found';
        resultPill.className = 'result-pill result-not';
        resultPill.style.display = 'inline-block';
      }
    }

    function resetState(){
      if(autoTimer){ clearInterval(autoTimer); autoTimer=null; }
      state = 'idle';
      foundIndex = -1;
      low = 0;
      high = arr.length - 1;
      mid = -1;
      setStatus('Idle — provide array and target, then Start.');
      logEl.textContent = 'No steps yet.';
      updateHighlights();
    }

    function start(){
      // validate array
      if(arr.length === 0){
        alert('Array is empty. Provide a comma-separated array of numbers.');
        return;
      }
      if(arr.some(x => isNaN(x))){
        alert('Array contains non-numeric values. Only numeric values are allowed.');
        return;
      }
      // ensure sorted
      for(let i=1;i<arr.length;i++){
        if(arr[i] < arr[i-1]){
          const ok = confirm('Array does not appear to be sorted ascending. Continue anyway?');
          if(!ok) return;
          break;
        }
      }
      // parse target
      const tRaw = targetInput.value.trim();
      if(tRaw.length === 0){
        alert('Please enter a target value.');
        return;
      }
      const t = Number(tRaw);
      if(isNaN(t)){
        alert('Target must be a number.');
        return;
      }
      target = t;
      // initialize indices
      low = 0;
      high = arr.length - 1;
      mid = -1;
      foundIndex = -1;
      state = 'running';
      setStatus(`Searching for ${target}...`);
      logEl.textContent = '';
      log(`Start search for ${target} in array of length ${arr.length}`);
      updateHighlights();
    }

    function step(){
      if(state === 'idle'){
        alert('Start the search first (press Start).');
        return;
      }
      if(state === 'finished'){
        return;
      }
      if(low > high){
        // not found
        state = 'finished';
        setStatus(`Target ${target} not found`, 'notfound');
        log(`Terminated: target not found (low=${low}, high=${high}).`);
        updateHighlights();
        return;
      }
      mid = Math.floor((low + high) / 2);
      log(`Checking mid=${mid} (value=${arr[mid]})`);
      updateHighlights();
      // compare
      if(arr[mid] === target){
        foundIndex = mid;
        state = 'finished';
        setStatus(`Target ${target} found at index ${mid}`, 'found');
        log(`Found target at index ${mid}.`);
        updateHighlights();
        return;
      }
      if(arr[mid] < target){
        log(`Value ${arr[mid]} < ${target} → move low to ${mid + 1}`);
        low = mid + 1;
      } else {
        log(`Value ${arr[mid]} > ${target} → move high to ${mid - 1}`);
        high = mid - 1;
      }
      updateHighlights();
      // check for next termination
      if(low > high){
        state = 'finished';
        setStatus(`Target ${target} not found`, 'notfound');
        log(`Terminated: target not found (low=${low}, high=${high}).`);
      } else {
        setStatus(`Searching... (low=${low}, high=${high})`);
      }
    }

    function runToCompletion(){
      if(state !== 'running'){
        alert('Start the search first (press Start).');
        return;
      }
      runBtn.disabled = true;
      stepBtn.disabled = true;
      autoTimer = setInterval(() => {
        // single step each 550ms
        step();
        if(state === 'finished'){
          clearInterval(autoTimer);
          autoTimer = null;
          runBtn.disabled = false;
          stepBtn.disabled = false;
        }
      }, 550);
    }

    // initialize
    renderArray();

    applyArray.addEventListener('click', () => {
      const parsed = parseArray(arrayInput.value);
      if(parsed.length === 0){
        alert('Provide at least one numeric element in the array.');
        return;
      }
      arr = parsed;
      resetState();
      renderArray();
    });

    startSearch.addEventListener('click', () => {
      start();
      updateHighlights();
    });

    stepBtn.addEventListener('click', () => {
      step();
    });

    runBtn.addEventListener('click', () => {
      runToCompletion();
    });

    resetBtn.addEventListener('click', () => {
      if(confirm('Reset search and UI to initial state?')){
        if(autoTimer){ clearInterval(autoTimer); autoTimer=null; }
        arr = parseArray(arrayInput.value);
        resetState();
        renderArray();
      }
    });

    // keyboard shortcuts
    window.addEventListener('keydown', (e) => {
      if(e.key === ' ' && document.activeElement.tagName !== 'INPUT'){
        e.preventDefault();
        step();
      }
      if(e.key === 'r' && (e.ctrlKey || e.metaKey)){
        e.preventDefault();
        runToCompletion();
      }
    });

    // initial small hint
    log('Ready. Press Start to initialize the search, then Step to walk it.');
  </script>
</body>
</html>

