    <label class="small-muted">Target: <input id="target" type="number" value="23" style="width:100px;margin-left:8px;padding:6px;border-radius:6px;border:1px solid #d1e6e8"></label>

    <button class="btn" id="stepBtn">Step</button>
    <button class="btn ghost small" id="autoBtn">Auto</button>
    <button class="btn secondary small" id="resetBtn">Reset</button>
    <button class="btn ghost small" id="randomBtn">Random</button>

    <label style="margin-left:auto" class="small-muted">Array length:
      <select id="arrLen" class="array-size" aria-label="Array length">
        <option>7</option><option>9</option><option>11</option><option>13</option><option>15</option>
      </select>
    </label>
  </div>

  <div id="arrayWrap" class="array-box" tabindex="0" aria-live="polite" aria-label="Array elements">
    <!-- cells go here -->
  </div>

  <div class="status" id="status">
    <div id="stepDesc">Press Step to begin. Low = 0, High = n-1.</div>
    <div class="legend">
      <div style="display:flex;gap:8px;align-items:center">
        <div><span class="sw" style="background:var(--box)"></span> normal</div>
        <div><span class="sw" style="background:#fff5e6;border:2px solid #f59e0b"></span> mid</div>
        <div><span class="sw" style="background:rgba(16,185,129,0.08);border:2px solid rgba(14,165,164,0.14)"></span> current range</div>
      </div>
    </div>
  </div>

  <div class="notes">
    Controls: Step advances one iteration. Auto toggles automatic stepping (500ms). Reset clears state to start. Edit array cells directly; values must remain sorted ascending. Use Random to generate a new sorted array.
  </div>

  <footer>
    Tip: press Enter to step, Space to toggle Auto. The visualizer validates that the array is sorted before proceeding.
  </footer>
</div>

<script>
(function(){
  const arrWrap = document.getElementById('arrayWrap');
  const stepBtn = document.getElementById('stepBtn');
  const autoBtn = document.getElementById('autoBtn');
  const resetBtn = document.getElementById('resetBtn');
  const randomBtn = document.getElementById('randomBtn');
  const targetInput = document.getElementById('target');
  const stepDesc = document.getElementById('stepDesc');
  const arrLenSelect = document.getElementById('arrLen');

  let arr = [];
  let low = 0, high = 0, mid = -1;
  let running = false;
  let timer = null;
  let started = false;
  let foundIndex = null;

  function clamp(n, a, b){ return Math.max(a, Math.min(b, n)); }

  function makeRandomSorted(n){
    const base = Math.floor(Math.random()*6);
    const res = [];
    let cur = base;
    for(let i=0;i<n;i++){
      cur += 1 + Math.floor(Math.random()*4);
      res.push(cur);
    }
    return res;
  }

  function buildArray(n){
    arr = makeRandomSorted(n);
    low = 0; high = arr.length-1; mid = -1; started=false; foundIndex = null;
    render();
    updateDesc('Ready. Low = 0, High = ' + (arr.length-1) + '.');
  }

  function render(){
    arrWrap.innerHTML = '';
    arr.forEach((v,i)=>{
      const cell = document.createElement('div');
      cell.className = 'cell';
      cell.setAttribute('data-idx', i);
      if (i>=low && i<=high) cell.classList.add('range');
      if (i===mid) cell.classList.add('mid');
      if (i===foundIndex) cell.classList.add('found');

      const idx = document.createElement('div');
      idx.className='idx';
      idx.textContent = i;
      cell.appendChild(idx);

      const inp = document.createElement('input');
      inp.type='number';
      inp.value = v;
      inp.setAttribute('aria-label', 'Value at index '+i);
      inp.addEventListener('change', e=>{
        const newVal = Number(e.target.value);
        arr[i] = newVal;
        if (!isSorted(arr)){
          updateDesc('Array must be sorted ascending. Fix values before stepping.', true);
          // highlight unsorted
          cell.style.borderColor = '#fca5a5';
        } else {
          // restore normal
          const cells = arrWrap.querySelectorAll('.cell');
          cells.forEach(c=>c.style.borderColor='');
          updateDesc('Array updated. Ready.');
        }
        // reset algorithm state when array changes
        resetState();
        render();
      });
      cell.appendChild(inp);
      arrWrap.appendChild(cell);
    });
  }

  function isSorted(a){
    for(let i=1;i<a.length;i++) if (Number(a[i]) < Number(a[i-1])) return false;
    return true;
  }

  function updateDesc(txt, isError){
    stepDesc.textContent = txt;
    stepDesc.style.color = isError ? 'var(--danger)' : '';
  }

  function resetState(){
    low = 0; high = arr.length-1; mid = -1; started=false; foundIndex = null;
    running = false;
    if (timer) { clearInterval(timer); timer=null; autoBtn.textContent='Auto'; }
  }

  function stepOnce(){
    if (!isSorted(arr)){
      updateDesc('Array not sorted. Fix it before stepping.', true);
      return;
    }
    if (foundIndex !== null){
      updateDesc('Search already finished. Reset to run again.');
      return;
    }
    const target = Number(targetInput.value);
    if (!started){
      updateDesc('Starting search for ' + target + '. Low='+low+', High='+high+'.');
      started = true;
    }
    if (low > high){
      updateDesc('Not found: range exhausted. Target '+target+' is not in array.', true);
      foundIndex = null;
      mid = -1;
      render();
      return;
    }
    mid = Math.floor((low + high)/2);
    render();
    updateDesc('Checking mid = '+mid+' (value '+arr[mid]+') against target '+target+'.');
    // decide outcome after a small visual pause to let user see mid
    // immediate logic (since "Step" is single iteration): if equal -> found; else adjust low/high
    if (Number(arr[mid]) === target){
      foundIndex = mid;
      updateDesc('Found target '+target+' at index '+mid+'.');
      render();
      return;
    } else if (Number(arr[mid]) < target){
      low = mid + 1;
      updateDesc('Value '+arr[mid]+' < '+target+'. Move low to '+low+'.');
      render();
      return;
    } else {
      high = mid - 1;
      updateDesc('Value '+arr[mid]+' > '+target+'. Move high to '+high+'.');
      render();
      return;
    }
  }

  function toggleAuto(){
    if (running){
      running = false;
      clearInterval(timer); timer = null;
      autoBtn.textContent = 'Auto';
      updateDesc('Auto stopped.');
      return;
    }
    if (!isSorted(arr)){
      updateDesc('Array not sorted. Fix it before auto-running.', true);
      return;
    }
    running = true;
    autoBtn.textContent = 'Stop';
    updateDesc('Auto running...');
    timer = setInterval(()=>{
      if (foundIndex !== null || low>high){
        running = false; clearInterval(timer); timer=null; autoBtn.textContent='Auto';
        if (foundIndex===null && low>high) updateDesc('Auto finished: not found.');
        return;
      }
      stepOnce();
    }, 500);
  }

  // event wiring
  stepBtn.addEventListener('click', ()=> stepOnce());
  autoBtn.addEventListener('click', ()=> toggleAuto());
  resetBtn.addEventListener('click', ()=>{
    resetState();
    render();
    updateDesc('Reset. Low = 0, High = '+(arr.length-1)+'.');
  });
  randomBtn.addEventListener('click', ()=>{
    resetState();
    buildArray(Number(arrLenSelect.value));
  });
  arrLenSelect.addEventListener('change', ()=>{
    buildArray(Number(arrLenSelect.value));
  });

  // keyboard shortcuts
  document.addEventListener('keydown', (e)=>{
    if (e.key === 'Enter') { e.preventDefault(); stepOnce(); }
    if (e.code === 'Space') { e.preventDefault(); toggleAuto(); }
  });

  // initialize
  buildArray(Number(arrLenSelect.value));

  // expose for debugging (optional)
  window._bs = {
    get state(){ return {arr,low,high,mid,foundIndex,started}; },
    step: stepOnce,
    reset: ()=>{ resetState(); render(); },
    random: ()=>{ buildArray(Number(arrLenSelect.value)); }
  };

})();
</script>
</body>
</html>

